void function() {
    int count;
    count = getValue(); // Noncompliant: declaration and initialization separated
}

void processFile() {
    std::string filename;
    bool isValid;

    filename = getFilename();
    isValid = checkFile(filename); // Noncompliant: late initialization
}

class Example {
public:
    void method() {
        double result;
        result = calculate(); // Noncompliant
    }
};

compliant:
void function() {
    int count = getValue(); // Compliant: initialization at declaration
}

void processFile() {
    std::string filename = getFilename(); // Compliant
    bool isValid = checkFile(filename);   // Compliant
}

class Example {
public:
    void method() {
        auto result = calculate(); // Compliant: immediate initialization
        double value{computeValue()}; // Compliant: brace initialization
    }
};
